diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..8a97f862929f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3205,6 +3205,23 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select (X && Y), C, (select X, A, B) -> select X, (select Y, C, A), B
+  // This happens when a nested select with a common condition is combined
+  // with an AND-like condition (select X, Y, false).
+  Value *X, *Y;
+  if (CondVal->hasOneUse() &&
+      match(CondVal, m_Select(m_Value(X), m_Value(Y), m_Zero()))) {
+    if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (FalseSI->hasOneUse() && FalseSI->getCondition() == X) {
+        Value *NewSel = Builder.CreateSelect(Y, TrueVal,
+                                             FalseSI->getTrueValue(),
+                                             SI.getName() + ".sel", &SI);
+        return SelectInst::Create(X, NewSel, FalseSI->getFalseValue());
+      }
+    }
+  }
+
+
   Value *NotCond;
   if (match(CondVal, m_Not(m_Value(NotCond))) &&
       !InstCombiner::shouldAvoidAbsorbingNotIntoSelect(SI)) {

